document.addEventListener('DOMContentLoaded', function() {
  initNavigation();
  initScrollAnimations();
  initHeaderScroll();
  initSmoothScroll();
  initFiveElementsInteraction();
  initMysticEffects();
  updateCartBadge();
});

function updateCartBadge() {
  const cartData = localStorage.getItem('daoessence_cart');
  const cartBadge = document.getElementById('cartBadge');
  const floatingCartBadge = document.getElementById('floatingCartBadge');
  
  if (cartBadge) {
    if (cartData) {
      try {
        const cart = JSON.parse(cartData);
        let totalQuantity = 0;
        if (Array.isArray(cart)) {
          cart.forEach(item => {
            totalQuantity += item.quantity;
          });
        } else if (cart.items && Array.isArray(cart.items)) {
          cart.items.forEach(item => {
            totalQuantity += item.quantity;
          });
        }
        cartBadge.textContent = totalQuantity;
        cartBadge.style.display = totalQuantity > 0 ? 'flex' : 'none';
      } catch (error) {
        cartBadge.style.display = 'none';
      }
    } else {
      cartBadge.style.display = 'none';
    }
  }
  
  if (floatingCartBadge) {
    if (cartData) {
      try {
        const cart = JSON.parse(cartData);
        let totalQuantity = 0;
        if (Array.isArray(cart)) {
          cart.forEach(item => {
            totalQuantity += item.quantity;
          });
        } else if (cart.items && Array.isArray(cart.items)) {
          cart.items.forEach(item => {
            totalQuantity += item.quantity;
          });
        }
        floatingCartBadge.textContent = totalQuantity;
        floatingCartBadge.style.display = totalQuantity > 0 ? 'flex' : 'none';
      } catch (error) {
        floatingCartBadge.style.display = 'none';
      }
    } else {
      floatingCartBadge.style.display = 'none';
    }
  }
}

window.addEventListener('storage', function(event) {
  if (event.key === 'daoessence_cart') {
    updateCartBadge();
  }
});

function toggleCart() {
  const pathname = window.location.pathname;
  if (pathname.includes('product-detail.html')) {
    const cartSidebar = document.querySelector('.cart-sidebar');
    const cartOverlay = document.querySelector('.cart-overlay');
    if (cartSidebar && cartOverlay) {
      if (cartSidebar.classList.contains('open')) {
        cartSidebar.classList.remove('open');
        cartOverlay.classList.remove('show');
      } else {
        cartSidebar.classList.add('open');
        cartOverlay.classList.add('show');
      }
    } else {
      console.log('Cart feature disabled - direct purchase mode');
    }
  } else {
    console.log('Cart feature disabled - direct purchase mode');
  }
}

function initNavigation() {
  const mobileMenuBtn = document.querySelector('.mobile-menu-btn');
  const navMenu = document.querySelector('.nav-menu');
  if (mobileMenuBtn && navMenu) {
    mobileMenuBtn.addEventListener('click', function() {
      navMenu.classList.toggle('active');
      this.classList.toggle('active');
      const spans = this.querySelectorAll('span');
      if (this.classList.contains('active')) {
        spans[0].style.transform = 'rotate(45deg) translate(8px, 8px)';
        spans[1].style.opacity = '0';
        spans[2].style.transform = 'rotate(-45deg) translate(8px, -8px)';
      } else {
        spans[0].style.transform = 'none';
        spans[1].style.opacity = '1';
        spans[2].style.transform = 'none';
      }
    });
    
    document.addEventListener('click', function(event) {
      if (!navMenu.contains(event.target) && event.target !== mobileMenuBtn) {
        navMenu.classList.remove('active');
        mobileMenuBtn.classList.remove('active');
        const spans = mobileMenuBtn.querySelectorAll('span');
        spans.forEach(span => {
          span.style.transform = 'none';
          span.style.opacity = '1';
        });
      }
    });
  }

  // Blog dropdown toggle (mobile)
  document.querySelectorAll('.nav-dropdown-trigger').forEach(trigger => {
    trigger.addEventListener('click', function(e) {
      if (window.innerWidth <= 768) {
        e.preventDefault();
        this.parentElement.classList.toggle('active');
      }
    });
  });
}

function initHeaderScroll() {
  const header = document.querySelector('.header');
  if (header) {
    const isHomePage = document.body.classList.contains('home-page') || 
                      window.location.pathname.endsWith('index.html') || 
                      window.location.pathname === '/' || 
                      window.location.pathname.endsWith('/');
    
    if (!isHomePage) {
      header.classList.add('scrolled');
    }
    window.addEventListener('scroll', function() {
      if (window.scrollY > 50) {
        header.classList.add('scrolled');
      } else if (isHomePage) {
        header.classList.remove('scrolled');
      }
    });
  }
}

function initScrollAnimations() {
  const elements = document.querySelectorAll('.scroll-animate');
  if (elements.length > 0) {
    const observerOptions = {
      threshold: 0.15,
      rootMargin: '0px 0px -50px 0px'
    };
    
    const observer = new IntersectionObserver(function(entries) {
      entries.forEach((entry, index) => {
        if (entry.isIntersecting) {
          setTimeout(function() {
            entry.target.classList.add('visible');
          }, 100 * index);
          observer.unobserve(entry.target);
        }
      });
    }, observerOptions);
    
    elements.forEach(element => {
      observer.observe(element);
    });
  }
}

function initSmoothScroll() {
  document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      const href = this.getAttribute('href');
      if (href !== '#') {
        e.preventDefault();
        const target = document.querySelector(href);
        if (target) {
          target.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }
    });
  });
}

function initFiveElementsInteraction() {
  const elementCards = document.querySelectorAll('.element-card');
  elementCards.forEach(card => {
    card.addEventListener('mouseenter', function() {
      const element = this.dataset.element;
      highlightRelatedElements(element);
    });
    card.addEventListener('mouseleave', function() {
      resetElementHighlights();
    });
  });
}

const fiveElementsRelations = {
  wood: {
    generates: 'fire',
    overcomes: 'earth',
    generatedBy: 'water',
    overcomeBy: 'metal',
    color: '#2D5A3D',
    name: 'Wood',
    traits: ['Growth', 'Creation', 'Benevolence']
  },
  fire: {
    generates: 'earth',
    overcomes: 'metal',
    generatedBy: 'wood',
    overcomeBy: 'water',
    color: '#8B2500',
    name: 'Fire',
    traits: ['Passion', 'Light', 'Etiquette']
  },
  earth: {
    generates: 'metal',
    overcomes: 'water',
    generatedBy: 'fire',
    overcomeBy: 'wood',
    color: '#8B7355',
    name: 'Earth',
    traits: ['Stability', 'Inclusiveness', 'Integrity']
  },
  metal: {
    generates: 'water',
    overcomes: 'wood',
    generatedBy: 'earth',
    overcomeBy: 'fire',
    color: '#C0C0C0',
    name: 'Metal',
    traits: ['Restraint', 'Justice', 'Righteousness']
  },
  water: {
    generates: 'wood',
    overcomes: 'fire',
    generatedBy: 'metal',
    overcomeBy: 'earth',
    color: '#1A3A4A',
    name: 'Water',
    traits: ['Wisdom', 'Flow', 'Adaptability']
  }
};

function highlightRelatedElements(element) {
  const relations = fiveElementsRelations[element];
  if (relations) {
    document.querySelectorAll('.element-card').forEach(card => {
      const cardElement = card.dataset.element;
      card.classList.remove('highlight-generate', 'highlight-overcome');
      if (cardElement === relations.generates) {
        card.classList.add('highlight-generate');
      } else if (cardElement === relations.overcomes) {
        card.classList.add('highlight-overcome');
      }
    });
  }
}

function resetElementHighlights() {
  document.querySelectorAll('.element-card').forEach(card => {
    card.classList.remove('highlight-generate', 'highlight-overcome');
  });
}

function initMysticEffects() {
  const mysticGlows = document.querySelectorAll('.mystic-glow');
  mysticGlows.forEach(glow => {
    glow.addEventListener('mousemove', function(e) {
      const rect = this.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      this.style.setProperty('--glow-x', x + 'px');
      this.style.setProperty('--glow-y', y + 'px');
    });
  });
  
  const energySymbols = document.querySelectorAll('.energy-symbol');
  energySymbols.forEach(symbol => {
    setInterval(function() {
      symbol.style.opacity = 0.3 * Math.random() + 0.7;
    }, 2000 + 3000 * Math.random());
  });
}

function initProductFilter() {
  const filterButtons = document.querySelectorAll('.filter-btn');
  const elements = document.querySelectorAll('[data-element]');
  
  filterButtons.forEach(button => {
    button.addEventListener('click', function() {
      filterButtons.forEach(btn => {
        btn.classList.remove('active');
      });
      this.classList.add('active');
      
      const filter = this.dataset.filter;
      elements.forEach(element => {
        if (filter === 'all' || element.dataset.element === filter) {
          element.style.display = 'block';
          setTimeout(function() {
            element.style.opacity = '1';
            element.style.transform = 'scale(1)';
          }, 50);
        } else {
          element.style.opacity = '0';
          element.style.transform = 'scale(0.95)';
          setTimeout(function() {
            element.style.display = 'none';
          }, 300);
        }
      });
    });
  });
}

function openBookingModal(serviceName, servicePrice) {
  const modal = document.createElement('div');
  modal.className = 'booking-modal';
  modal.innerHTML = `
    <div class="modal-overlay" onclick="closeBookingModal()"></div>
    <div class="modal-content">
      <button class="modal-close" onclick="closeBookingModal()">✕</button>
      <h3>Book Consultation - ${serviceName}</h3>
      <p class="specialty">Specialty: ${servicePrice}</p>
      <form class="booking-form" onsubmit="submitBooking(event)">
        <div class="form-group">
          <label>Name</label>
          <input type="text" required placeholder="Your Name">
        </div>
        <div class="form-group">
          <label>Birth Information</label>
          <input type="text" placeholder="Lunar Year/Month/Day/Hour (Optional)">
        </div>
        <div class="form-group">
          <label>Questions</label>
          <textarea required placeholder="Please describe your questions..."></textarea>
        </div>
        <div class="form-group">
          <label>Contact</label>
          <input type="email" required placeholder="Your Email">
        </div>
        <button type="submit" class="btn btn-primary">Submit Booking</button>
      </form>
    </div>
  `;
  document.body.appendChild(modal);
  document.body.style.overflow = 'hidden';
  setTimeout(function() {
    modal.classList.add('active');
  }, 10);
}

function closeBookingModal() {
  const modal = document.querySelector('.booking-modal');
  if (modal) {
    modal.classList.remove('active');
    setTimeout(function() {
      modal.remove();
      document.body.style.overflow = 'auto';
    }, 300);
  }
}

function submitBooking(event) {
  event.preventDefault();
  showNotification('Booking submitted successfully! We will contact you within 24 hours.', 'success');
  closeBookingModal();
}

function showNotification(message, type = 'info') {
  const notification = document.createElement('div');
  notification.className = `notification notification-${type}`;
  notification.innerHTML = `
    <span class="notification-icon">${type === 'success' ? '✓' : type === 'error' ? '✕' : 'ℹ'}</span>
    <span>${message}</span>
    <button class="notification-close" onclick="this.parentElement.remove()">✕</button>
  `;
  notification.style.cssText = `
    position: fixed;
    top: 100px;
    right: 20px;
    background: ${type === 'success' ? '#2D5A3D' : type === 'error' ? '#8B2500' : '#1A3A4A'};
    color: #F5F0E6;
    padding: 15px 25px;
    border-radius: 4px;
    box-shadow: 0 4px 15px rgba(0,0,0,0.2);
    display: flex;
    align-items: center;
    gap: 15px;
    z-index: 10000;
    animation: slideInRight 0.3s ease-out;
    border-left: 3px solid #D4AF37;
  `;
  document.body.appendChild(notification);
  setTimeout(function() {
    notification.style.animation = 'slideOutRight 0.3s ease-out';
    setTimeout(function() {
      notification.remove();
    }, 300);
  }, 5000);
}

function formatPrice(price, currency = 'USD') {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: currency
  }).format(price);
}

function debounce(func, wait) {
  let timeout;
  return function() {
    const context = this;
    const args = arguments;
    clearTimeout(timeout);
    timeout = setTimeout(function() {
      func.apply(context, args);
    }, wait);
  };
}

function throttle(func, limit) {
  let inThrottle;
  return function() {
    const context = this;
    const args = arguments;
    if (!inThrottle) {
      func.apply(context, args);
      inThrottle = true;
      setTimeout(function() {
        inThrottle = false;
      }, limit);
    }
  };
}

window.DAOEssence = {
  showNotification,
  openBookingModal,
  closeBookingModal,
  fiveElementsRelations,
  formatPrice
};

